	"dataSources": {
		"ds_0NhD1ePM": {
			"name": "index_rest",
			"options": {
				"query": "| rest /services/data/indexes"
			},
			"type": "ds.search"
		},
		"ds_1phnRxPX": {
			"name": "tstats_count_by_host",
			"options": {
				"query": "| tstats count where index=\"$index$\" by host \n| sort - count"
			},
			"type": "ds.chain"
		},
		"ds_5hhH7IMw": {
			"name": "panel_total_events",
			"options": {
				"extend": "ds_0NhD1ePM",
				"query": "| search title=\"$index$\"\n| stats sum(totalEventCount) as totalEventCount"
			},
			"type": "ds.chain"
		},
		"ds_7LctR8RJ": {
			"name": "panel_first_event",
			"options": {
				"extend": "ds_0NhD1ePM",
				"query": "| search title=\"$index$\"\n| search minTime=*-*\n| sort minTime\n| head 1\n| table minTime\n| eval minTime = substr(replace(minTime, \"T\", \" \"),1,19)"
			},
			"type": "ds.chain"
		},
		"ds_EHkGaLFV_ds_Rr6rLToc": {
			"name": "panel_source",
			"options": {
				"query": "| metadata type=sources index=$index$\n| table source  totalCount\n| sort - totalCount\n| rename totalCount as Count"
			},
			"type": "ds.chain"
		},
		"ds_RQ0Tb28l_ds_7LctR8RJ": {
			"name": "panel_last_event",
			"options": {
				"extend": "ds_0NhD1ePM",
				"query": "| search title=\"$index$\"\n| search maxTime=*-*\n| sort - maxTime\n| head 1\n| table maxTime\n| eval maxTime = substr(replace(maxTime, \"T\", \" \"),1,19)"
			},
			"type": "ds.chain"
		},
		"ds_Rr6rLToc": {
			"name": "panel_sourcetypes",
			"options": {
				"query": "| metadata type=sourcetypes index=$index$\n| table sourcetype  totalCount\n| sort - totalCount\n| rename totalCount as Count"
			},
			"type": "ds.chain"
		},
		"ds_VuuNqB5O": {
			"name": "List_IDX_size",
			"options": {
				"extend": "ds_0NhD1ePM",
				"query": "| search title=\"$index$\"\n| eval Index_size=round(currentDBSizeMB, 2)\n| table splunk_server  Index_size \n| sort splunk_server\n| rename totalEventCount as \"Count events\", Index_size as \"Size\", splunk_server as Indexer"
			},
			"type": "ds.chain"
		},
		"ds_ZS2E7HYC": {
			"name": "panel_count_by_indexer",
			"options": {
				"extend": "ds_0NhD1ePM",
				"query": "| search title=\"$index$\"\n| eval Index_size=round(currentDBSizeMB/1024, 2)\n| table splunk_server  totalEventCount\n| sort splunk_server\n| rename totalEventCount as \"Count\", Index_size as \"index size\", splunk_server as Indexer"
			},
			"type": "ds.chain"
		},
		"ds_eJp8SJi0_ds_ZS2E7HYC": {
			"name": "panel_count_by_indexer copy 1",
			"options": {
				"extend": "ds_0NhD1ePM",
				"query": "| search title=\"$index$\"\n| eval Index_size=round(currentDBSizeMB/1024, 2)\n| table splunk_server  totalEventCount\n| sort splunk_server\n| rename totalEventCount as \"Count events\", Index_size as \"index size\", splunk_server as Indexer"
			},
			"type": "ds.chain"
		},
		"ds_kWk387Ud": {
			"name": "psnel_name_index",
			"options": {
				"query": "| makeresults\n| eval index=\"$index$\"\n| table index"
			},
			"type": "ds.chain"
		},
		"ds_m3xxLkY3": {
			"name": "panel_tstats_count_by_time",
			"options": {
				"query": "| tstats count where index=\"$index$\" by _time\n| timechart sum(count) as count"
			},
			"type": "ds.search"
		},
		"ds_s2K9db8u": {
			"name": "input_list_index",
			"options": {
				"extend": "ds_0NhD1ePM",
				"query": "| search NOT title IN (_*, ba_test)\n| dedup title\n| fields + title\n| rename title as index\n| sort index"
			},
			"type": "ds.chain"
		},
		"ds_swyvyT6g_ds_m3xxLkY3": {
			"name": "panel_tstats_count_by_time_host",
			"options": {
				"query": "| tstats count where index=\"$index$\" by _time, host\n| timechart sum(count) as count by host"
			},
			"type": "ds.search"
		}
	},
